mapper.select:
SELECT t.doctorId, t.doctorName, t.department, IFNULL(r.cnt, 0) AS registrationCount, IFNULL(o.cnt, 0) AS outpatientCount, IFNULL(i.cnt, 0) AS inpatientCount, IFNULL(r.fee, 0) + IFNULL(o.fee, 0) AS totalAmount FROM ( SELECT DISTINCT doctor_id AS doctorId, doctor_name AS doctorName, department FROM registration WHERE deleted = 0 AND doctor_id IS NOT NULL UNION SELECT DISTINCT doctor_id AS doctorId, doctor_name AS doctorName, department FROM outpatient_record WHERE deleted = 0 AND doctor_id IS NOT NULL UNION SELECT DISTINCT doctor_id AS doctorId, doctor_name AS doctorName, department FROM inpatient WHERE deleted = 0 AND doctor_id IS NOT NULL ) t LEFT JOIN ( SELECT doctor_id, COUNT(*) AS cnt, IFNULL(SUM(registration_fee), 0) AS fee FROM registration WHERE deleted = 0
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
GROUP BY doctor_id ) r ON t.doctorId = r.doctor_id LEFT JOIN ( SELECT doctor_id, COUNT(*) AS cnt, IFNULL(SUM(total_amount), 0) AS fee FROM outpatient_record WHERE deleted = 0
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
GROUP BY doctor_id ) o ON t.doctorId = o.doctor_id LEFT JOIN ( SELECT doctor_id, COUNT(*) AS cnt FROM inpatient WHERE deleted = 0
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
GROUP BY doctor_id ) i ON t.doctorId = i.doctor_id WHERE 1 = 1
AND t.department = #{department}
ORDER BY totalAmount DESC

SELECT d.id AS drugId, d.drug_code AS drugCode, d.name AS drugName, d.specification, d.unit, IFNULL(d.stock, 0) - IFNULL(SUM(CASE WHEN l.type = 1 THEN l.quantity ELSE 0 END), 0) + IFNULL(SUM(CASE WHEN l.type = 2 THEN l.quantity ELSE 0 END), 0) AS beginStock, IFNULL(SUM(CASE WHEN l.type = 1 THEN l.quantity ELSE 0 END), 0) AS inQuantity, IFNULL(SUM(CASE WHEN l.type = 2 THEN l.quantity ELSE 0 END), 0) AS outQuantity, IFNULL(d.stock, 0) AS endStock, d.price AS unitPrice, IFNULL(d.stock, 0) * d.price AS stockValue FROM drug d LEFT JOIN drug_stock_log l ON d.id = l.drug_id
AND DATE(l.create_time) >= #{startDate}
AND DATE(l.create_time) <= #{endDate}
WHERE d.deleted = 0 GROUP BY d.id, d.drug_code, d.name, d.specification, d.unit, d.stock, d.price ORDER BY d.id

SELECT date, SUM(registrationCount) AS registrationCount, SUM(outpatientCount) AS outpatientCount, SUM(inpatientCount) AS inpatientCount, SUM(registrationCount) + SUM(outpatientCount) + SUM(inpatientCount) AS totalCount FROM ( SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS date, COUNT(*) AS registrationCount, 0 AS outpatientCount, 0 AS inpatientCount FROM registration WHERE deleted = 0
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
GROUP BY date UNION ALL SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS date, 0 AS registrationCount, COUNT(*) AS outpatientCount, 0 AS inpatientCount FROM outpatient_record WHERE deleted = 0
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
GROUP BY date UNION ALL SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS date, 0 AS registrationCount, 0 AS outpatientCount, COUNT(*) AS inpatientCount FROM inpatient WHERE deleted = 0
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
GROUP BY date ) AS patient_trend GROUP BY date ORDER BY date DESC
